    switch (*(s32*)((s32)battleWork + 0x1C80)) {
        case 1:
            msg += 0x1A0;
            break;
        case 2:
            msg += 0x1B8;
            break;
        case 4:
            msg += 0x1D0;
            break;
        case 5:
            msg += 0x1F0;
            break;
        case 6:
            msg += 0x214;
            break;
        default:
            msg += 0x230;
            break;
    }

    evtSetValue(evt, dst, (s32)msg);
