    if (*(s8*)((s32)weapon + 0x82) > 0 && *(s8*)((s32)weapon + 0x83) > 0) {
        return 1;
    }
    if (*(s8*)((s32)weapon + 0x84) > 0 && *(s8*)((s32)weapon + 0x85) > 0) {
        return 1;
    }
